import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

public class XSSFixedCode {
    public static void main(String[] args) {
        // Simulating user input from a form or any external source
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Properly encoding user input to prevent XSS attacks
        String sanitizedInput = "";
        try {
            sanitizedInput = ESAPI.encoder().encodeForHTML(userInput);
        } catch (EncodingException e) {
            System.err.println("Encoding error: " + e.getMessage());
            return;
        }

        // Output the sanitized result to the console
        String output = "Welcome, " + sanitizedInput;
        System.out.println(output);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
